// generar_209_orden_cuidados_rutinas_conversacionales.js
// CHIQUI Entre Señales — Nuevo orden de Cuidados + Rutinas que conversan
//
// Qué hace este script:
// 1) app/registro-diario/page.tsx → nuevo orden de grupos: Veterinario
//    y salud → Prevención → Alimentación → Higiene y bienestar →
//    Arenero (solo gatos).
// 2) app/dashboard/page.tsx → mismo orden en "Cuidados recientes".
// 3) app/analisis/page.tsx → las Rutinas de cuidado ahora le hablan al
//    tutor: "Habitualmente compras alimento cada 9 días", "Sueles
//    limpiar el arenero día por medio", "Te tocaría de nuevo en 4
//    días". Eventos médicos poco frecuentes mantienen frase neutra.
//
// No requiere SQL: no hay columnas nuevas, solo UI y textos.
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_209_orden_cuidados_rutinas_conversacionales.js

const fs = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "app/registro-diario/page.tsx",
    base64: ""
  },
  {
    ruta: "app/analisis/page.tsx",
    base64: ""
  },
  {
    ruta: "app/dashboard/page.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('')
  console.log('Listo. 3 archivos escritos correctamente.')
  console.log('No hay SQL esta vez. Puedes hacer git add / commit / push directo.')
} else {
  console.error('')
  console.error('Terminó con ' + errores + ' error(es). NO hagas git push todavía.')
  process.exit(1)
}
